def write(p,d):p.parent.mkdir(parents=True,exist_ok=True);p.write_text(json.dumps(d,indent=2,ensure_ascii=False)+"\n",encoding="utf-8")
def rows(s):return [tuple(x.split("|")) for x in s.split(";")]
def model(base,k,n,years,c):
 p=base/k; files={x:f"{x}.json" for x in ("models","procedures","modules","wiring","service_functions","notes","photos")}
 write(p/"manifest.json",{"schema_version":"2.1","updated_at":TODAY,"manufacturer":{"id":base.name,"name":c[0]},"model":{"id":k,"name":n},"version":1,"files":files,"verification":{"status":"research_in_progress","market":"UK","drive_side":"RHD"}})
 variants=[{"type":x,"status":"research_required"} for x in ("keyed","slot_key","proximity","KESSY_or_keyless","smart_key")]
 write(p/"models.json",{"schema_version":"2.1","model":n,"market":"UK","drive_side":"RHD","generations":[{"id":k+"_uk_generations","name":n+" UK generations","years":years,"platform":"Generation-specific platform requires confirmation","immobiliser_family":c[2],"key_variants":variants,"status":"partially_verified"}],"sources":{"official_range":{"publisher":c[0],"url":c[1],"checked_at":TODAY,"confidence":"high","supports":["UK model-family coverage"]}}})
 write(p/"procedures.json",{"schema_version":"2.1","model":n,"procedures":[{"id":op+"_"+v,"name":op.replace("akl","All keys lost").replace("add_key","Add key")+" - "+v,"method":"No generation-specific procedure recorded","status":"research_required"} for v in ("keyed","slot_key","proximity","keyless","smart_key") for op in ("add_key","akl")]})
 write(p/"modules.json",{"schema_version":"2.1","model":n,"modules":[{"id":"body_security","name":"Body/security controller","role":"Exact BSI, UCH, BCM or equivalent requires generation evidence","location":"UK RHD location not verified","status":"research_required"},{"id":"keyless_controller","name":"Keyless/proximity controller where fitted","location":"UK RHD location not verified","status":"research_required"}]})
 write(p/"wiring.json",{"schema_version":"2.1","model":n,"connections":[{"id":"obd","name":"OBD-II connector","location":"UK RHD location not verified","status":"research_required"},{"id":"bench","name":"Bench connection","notes":"No wiring, EEPROM, MCU or adapter claim recorded.","status":"research_required"}]})
 write(p/"service_functions.json",{"schema_version":"2.1","model":n,"functions":[{"id":"key_learning","name":"Key learning","availability":"Generation and tool dependent","status":"research_required"}]})
 write(p/"notes.json",{"schema_version":"2.1","model":n,"notes":[{"title":"Phase 1 scope","text":"UK coverage and year span only; generation breakpoints, platforms and locksmith data require Phase 2 evidence."},{"title":"Shared architecture boundary","text":c[2]+". No procedure or location is inherited from a related brand."}],"status":"research_in_progress"})
 write(p/"photos.json",{"schema_version":"2.1","model":n,"photos":[],"required":["UK RHD OBD and module locations","Key variants and module part numbers"],"status":"awaiting_verified_images"})
def main():
 a=argparse.ArgumentParser();a.add_argument("manufacturer",choices=CFG);m=a.parse_args().manufacturer;c=CFG[m];base=ROOT/"database"/"vehicles"/m; rr=rows(c[3])
 for k,n,y in rr:model(base,k,n,y,c)
 write(base/"manifest.json",{"schema_version":"2.1","updated_at":TODAY,"manufacturer":{"id":m,"name":c[0],"market":"UK","drive_side":"RHD"},"version":1,"models":{k:{"name":n,"version":1,"manifest":k+"/manifest.json","status":"research_in_progress"} for k,n,y in rr},"status":"research_in_progress","sources":{"official_range":{"url":c[1]}}})
 for p in (ROOT/"manifest.json",ROOT/"database"/"manifest.json"):
  d=json.loads(p.read_text(encoding="utf-8"));d["manufacturers"][m]={"name":c[0],"version":1,"manifest":f"database/vehicles/{m}/manifest.json","status":"research_in_progress","updated_at":TODAY};write(p,d)
 print(f"created {c[0]} Phase-1 coverage ({len(rr)} models)")
if __name__=="__main__":main()
